from __future__ import annotations

from html import escape
from pathlib import Path


OUT = Path("output/pdf/detailed-feasibility-study-example.html")


def money(value: float) -> str:
    return f"{value:,.0f}"


def table(headers: list[str], rows: list[list[object]]) -> str:
    head = "".join(f"<th>{escape(str(h))}</th>" for h in headers)
    body = "".join("<tr>" + "".join(f"<td>{escape(str(v))}</td>" for v in row) + "</tr>" for row in rows)
    return f"<table><thead><tr>{head}</tr></thead><tbody>{body}</tbody></table>"


def section(number: str, title: str, intro: str, content: str, page_break: bool = True) -> str:
    cls = "section page-break" if page_break else "section"
    return f"<section class='{cls}'><div class='section-kicker'>القسم {number}</div><h2>{title}</h2><p class='intro'>{intro}</p>{content}</section>"


